// Logger with structured output (no sensitive data)
function log(level, message, meta = {}) {
  const entry = {
    timestamp: new Date().toISOString(),
    level,
    message,
    traceId: meta.traceId || 'unknown',
    ...Object.fromEntries(
      Object.entries(meta).filter(([key]) => !['password', 'token', 'secret', 'payload'].includes(key))
    ),
  };
  if (level === 'error') {
    console.error(JSON.stringify(entry));
  } else {
    console.log(JSON.stringify(entry));
  }
}

// Validate and sanitize string input
function sanitizeString(input, maxLength = 255) {
  if (typeof input !== 'string') return null;
  return input.slice(0, maxLength).trim();
}

// Validate UUID format
function isValidUUID(str) {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(str);
}

// Validate that column names are allowed for a given table
function validateColumns(table, columns) {
  if (!ALLOWED_TABLES.has(table)) return false;
  const allowedCols = ALLOWED_COLUMNS[table];
  if (!allowedCols) return false;
  return columns.every((col) => allowedCols.has(col));
}

// Validate message schema
function validateMessage(message) {
  if (!message || typeof message !== 'object') {
    throw new Error('Message must be a non-null object');
  }

  const { type, payload, correlationId } = message;

  if (!type || typeof type !== 'string') {
    throw new Error('Message type is required and must be a string');
  }

  if (!ALLOWED_MESSAGE_TYPES.has(type)) {
    throw new Error(`Unknown or disallowed message type: ${sanitizeString(type, 50)}`);
  }

  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
    throw new Error('Payload must be a non-null, non-array object');
  }

  if (correlationId && !isValidUUID(correlationId)) {
    throw new Error('correlationId must be a valid UUID');
  }

  return true;
}

// Parse JSON safely with size limit
function parseMessage(buffer, maxSize = 1024 * 64) {
  if (!Buffer.isBuffer(buffer)) {
    throw new Error('Expected a Buffer');
  }

  if (buffer.length > maxSize) {
    throw new Error(`Message exceeds maximum size of ${maxSize} bytes`);
  }

  const raw = buffer.toString('utf-8');

  // Prevent prototype pollution
  const parsed = JSON.parse(raw);
  if (parsed.__proto__ || parsed.constructor || parsed.prototype) {
    throw new Error('Message contains forbidden keys');
  }

  return parsed;
}

// Audit log entry for every processed message
async function writeAuditLog(traceId, eventType, entityId, success, errorMessage = null) {
  try {
    await pool.query(
      `INSERT INTO audit_log (id, event_type, entity_id, payload, created_at)
       VALUES ($1, $2, $3, $4, NOW())`,
      [
        randomUUID(),
        sanitizeString(eventType, 50),
        sanitizeString(entityId, 100),
        JSON.stringify({ success, errorMessage: errorMessage ? sanitizeString(errorMessage, 500) : null, traceId }),
      ]
    );
  } catch (err) {
    log('error', 'Failed to write audit log', { traceId, error: err.message });
  }
}

