// Process a single message
async function processMessage(msg, channel) {
  const traceId = randomUUID();
  let parsedMessage = null;
  let entityId = null;

  try {
    parsedMessage = parseMessage(msg.content);
    validateMessage(parsedMessage);

    const { type, payload, correlationId } = parsedMessage;
    const effectiveTraceId = correlationId || traceId;

    log('info', 'Processing message', { traceId: effectiveTraceId, type });

    const handler = messageHandlers[type];
    if (!handler) {
      throw new Error(`No handler registered for message type: ${type}`);
    }

    entityId = await handler(payload, effectiveTraceId);

    await writeAuditLog(effectiveTraceId, type, entityId || 'unknown', true);

    // Acknowledge message only after successful processing
    channel.ack(msg);
    log('info', 'Message processed successfully', { traceId: effectiveTraceId, type });
  } catch (err) {
    log('error', 'Failed to process message', {
      traceId,
      error: err.message,
      type: parsedMessage?.type || 'unknown',
    });

    await writeAuditLog(traceId, parsedMessage?.type || 'unknown', entityId || 'unknown', false, err.message);

    // Reject and don't requeue malformed messages; requeue transient failures
    const isValidationError =
      err.message.includes('required') ||
      err.message.includes('Invalid') ||
      err.message.includes('Unknown') ||
      err.message.includes('disallowed') ||
      err.message.includes('forbidden') ||
      err.message.includes('exceeds') ||
      err.message.includes('must be');

    if (isValidationError) {
      // Dead-letter: don't requeue
      channel.nack(msg, false, false);
      log('warn', 'Message rejected (validation error), sent to DLQ', { traceId });
    } else {
      // Transient error: requeue with limit via delivery count
      const deliveryCount = (msg.properties.headers && msg.properties.headers['x-delivery-count']) || 0;
      if (deliveryCount >= 3) {
        channel.nack(msg, false, false);
        log('warn', 'Message rejected after max retries, sent to DLQ', { traceId, deliveryCount });
      } else {
        channel.nack(msg, false, true);
        log('warn', 'Message requeued for retry', { traceId, deliveryCount });
      }
    }
  }
}

// Main service startup
async function startService() {
  const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
  const QUEUE_NAME = process.env.QUEUE_NAME || 'events_queue';
  const DLQ_NAME = `${QUEUE_NAME}.dlq`;
  const DLX_NAME = `${QUEUE_NAME}.dlx`;
  const PREFETCH_COUNT = parseInt(process.env.PREFETCH_COUNT, 10) || 10;

  let connection = null;
  let channel = null;

  try {
    // Connect with heartbeat for connection health
    connection = await amqplib.connect(RABBITMQ_URL, {
      heartbeat: 30,
    });

    connection.on('error', (err) => {
      log('error', 'RabbitMQ connection error', { error: err.message });
    });

    connection.on('close', () => {
      log('warn', 'RabbitMQ connection closed, attempting reconnect...');
      setTimeout(startService, 5000);
    });

    channel = await connection.createChannel();

    // Set prefetch to limit concurrent processing
    await channel.prefetch(PREFETCH_COUNT);

    // Set up dead-letter exchange and queue
    await channel.assertExchange(DLX_NAME, 'direct', { durable: true });
    await channel.assertQueue(DLQ_NAME, {
      durable: true,
      arguments: {
        'x-message-ttl': 86400000, // 24 hours
      },
    });
    await channel.bindQueue(DLQ_NAME, DLX_NAME, QUEUE_NAME);

    // Set up main queue with dead-letter configuration
    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': DLX_NAME,
        'x-dead-letter-routing-key': QUEUE_NAME,
        'x-max-length': 100000,
      },
    });

    log('info', 'Connected to RabbitMQ, consuming messages', {
      traceId: 'startup',
      queue: QUEUE_NAME,
      prefetch: PREFETCH_COUNT,
    });

    // Start consuming
    await channel.consume(QUEUE_NAME, (msg) => {
      if (msg !== null) {
        processMessage(msg, channel);
      }
    });
  } catch (err) {
    log('error', 'Failed to start service', { traceId: 'startup', error: err.message });

    // Clean up on failure
    if (channel) {
      try {
        await channel.close();
      } catch (_) {}
    }
    if (connection) {
      try {
        await connection.close();
      } catch (_) {}
    }

    // Retry connection
    log('info', 'Retrying connection in 5 seconds...', { traceId: 'startup' });
    setTimeout(startService, 5000);
  }
}

// Graceful shutdown
async function gracefulShutdown(signal) {
  log('info', `Received ${signal}, shutting down gracefully...`, { traceId: 'shutdown' });

  try {
    await pool.end();
    log('info', 'Database pool closed', { traceId: 'shutdown' });
  } catch (err) {
    log('error', 'Error closing database pool', { traceId: 'shutdown', error: err.message });
  }

  process.exit(0);
}

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));

// Handle uncaught errors
process.on('uncaughtException', (err) => {
  log('error', 'Uncaught exception', { traceId: 'uncaught', error: err.message });
  process.exit(1);
});

process.on('unhandledRejection', (reason) => {
  log('error', 'Unhandled rejection', {
    traceId: 'unhandled',
    error: reason instanceof Error ? reason.message : String(reason),
  });
  process.exit(1);
});

// Health check endpoint
const http = require('http');
const healthServer = http.createServer(async (req, res) => {
  if (req.method === 'GET' && req.url === '/health') {
    try {
      await pool.query('SELECT 1');
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ status: 'healthy', timestamp: new Date().toISOString() }));
    } catch (err) {
      res.writeHead(503, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ status: 'unhealthy', timestamp: new Date().toISOString() }));
    }
  } else {
    res.writeHead(404);
    res.end();
  }
});

const HEALTH_PORT = parseInt(process.env.HEALTH_PORT, 10) || 3000;
healthServer.listen(HEALTH_PORT, '127.0.0.1', () => {
  log('info', `Health check server listening on port ${HEALTH_PORT}`, { traceId: 'startup' });
});

// Start the service
startService();

